    25→
    26→const (
    27→	// MetricName is a special label name that represent a metric name.
    28→	//
    29→	// Deprecated: Instead, consider using schema.Metadata structure and its methods for consistent metadata behaviour with the newly added __type__ and __unit__ labels. Alternatively use github.com/prometheus/common/model.MetricNameLabel for the direct replacement.
    30→	//
    31→	// labels package is providing label transport, agnostic to semantic meaning of each label.
    32→	MetricName = "__name__"
    33→
    34→	AlertName   = "alertname"
    35→	BucketLabel = "le"
    36→
    37→	labelSep = '\xfe' // Used at beginning of `Bytes` return.
    38→	sep      = '\xff' // Used between labels in `Bytes` and `Hash`.
    39→)
    40→
    41→var seps = []byte{sep} // Used with Hash, which has no WriteByte method.
    42→
    43→// Label is a key/value a pair of strings.
    44→type Label struct {
    45→	Name, Value string
    46→}
    47→
    48→func (ls Labels) String() string {
    49→	return ls.stringImpl(true)
    50→}
    51→
    52→// StringNoSpace is like String but does not add a space after commas.
    53→func (ls Labels) StringNoSpace() string {
    54→	return ls.stringImpl(false)
    55→}
    56→
    57→func (ls Labels) stringImpl(addSpace bool) string {
    58→	var bytea [1024]byte // On stack to avoid memory allocation while building the output.
    59→	b := bytes.NewBuffer(bytea[:0])
    60→
    61→	b.WriteByte('{')
    62→	i := 0
    63→	ls.Range(func(l Label) {
    64→		if i > 0 {
    65→			b.WriteByte(',')
    66→			if addSpace {
    67→				b.WriteByte(' ')
    68→			}
    69→		}
    70→		if !model.LegacyValidation.IsValidLabelName(l.Name) {
    71→			b.Write(strconv.AppendQuote(b.AvailableBuffer(), l.Name))
    72→		} else {
    73→			b.WriteString(l.Name)
    74→		}
    75→		b.WriteByte('=')
    76→		b.Write(strconv.AppendQuote(b.AvailableBuffer(), l.Value))
    77→		i++
    78→	})
    79→	b.WriteByte('}')
    80→	return b.String()
    81→}
    82→
    83→// MarshalJSON implements json.Marshaler.
    84→func (ls Labels) MarshalJSON() ([]byte, error) {
    85→	return json.Marshal(ls.Map())
    86→}
    87→
    88→// UnmarshalJSON implements json.Unmarshaler.
    89→func (ls *Labels) UnmarshalJSON(b []byte) error {
    90→	var m map[string]string
    91→
    92→	if err := json.Unmarshal(b, &m); err != nil {
    93→		return err
    94→	}
    95→
    96→	*ls = FromMap(m)
    97→	return nil
    98→}
    99→
   100→// MarshalYAML implements yaml.Marshaler.
   101→func (ls Labels) MarshalYAML() (any, error) {
   102→	return ls.Map(), nil
   103→}
   104→
   105→// UnmarshalYAML implements yaml.Unmarshaler.
   106→func (ls *Labels) UnmarshalYAML(unmarshal func(any) error) error {
   107→	var m map[string]string
   108→
   109→	if err := unmarshal(&m); err != nil {
   110→		return err
   111→	}
   112→
   113→	*ls = FromMap(m)
   114→	return nil
   115→}
   116→
   117→// IsValid checks if the metric name or label names are valid.
   118→func (ls Labels) IsValid(validationScheme model.ValidationScheme) bool {
   119→	err := ls.Validate(func(l Label) error {
   120→		if l.Name == model.MetricNameLabel {
   121→			// If the default validation scheme has been overridden with legacy mode,
   122→			// we need to call the special legacy validation checker.
   123→			if !validationScheme.IsValidMetricName(l.Value) {
   124→				return strconv.ErrSyntax
   125→			}
   126→		}
   127→		if !validationScheme.IsValidLabelName(l.Name) || !model.LabelValue(l.Value).IsValid() {
   128→			return strconv.ErrSyntax
   129→		}
   130→		return nil
   131→	})
   132→	return err == nil
   133→}
   134→
   135→// Map returns a string map of the labels.
   136→func (ls Labels) Map() map[string]string {
   137→	m := make(map[string]string)
   138→	ls.Range(func(l Label) {
   139→		m[l.Name] = l.Value
   140→	})
   141→	return m
   142→}
   143→
   144→// FromMap returns new sorted Labels from the given map.
   145→func FromMap(m map[string]string) Labels {
   146→	l := make([]Label, 0, len(m))
   147→	for k, v := range m {
   148→		l = append(l, Label{Name: k, Value: v})
   149→	}
   150→	return New(l...)
   151→}
