   763→func (it *chunkedSeriesIterator) Seek(t int64) chunkenc.ValueType {
   764→	if it.err != nil {
   765→		return chunkenc.ValNone
   766→	}
   767→	if len(it.chunks) == 0 {
   768→		return chunkenc.ValNone
   769→	}
   770→
   771→	startIdx := it.idx
   772→	it.idx += sort.Search(len(it.chunks)-startIdx, func(i int) bool {
   773→		return it.chunks[startIdx+i].MaxTimeMs >= t
   774→	})
