   776→		it.resetIterator()
   777→	} else {
   778→		ts := it.cur.AtT()
   779→		if ts >= t {
   780→			return it.valType
   781→		}
   782→	}
   783→
   784→	for it.valType = it.cur.Next(); it.valType != chunkenc.ValNone; it.valType = it.cur.Next() {
   785→		ts := it.cur.AtT()
   786→		if ts > it.maxt {
   787→			it.chunks = nil // Exhaust this iterator so follow-up calls to Next or Seek return fast.
   788→			return chunkenc.ValNone
   789→		}
   790→		if ts >= t && ts >= it.mint {
   791→			return it.valType
   792→		}
   793→	}
   794→
   795→	it.valType = chunkenc.ValNone
   796→	return it.valType
   797→}
