   850→// validateLabelsAndMetricName validates the label names/values and metric names returned from remote read,
   851→// also making sure that there are no labels with duplicate names.
   852→func validateLabelsAndMetricName(ls []prompb.Label) error {
   853→	for i, l := range ls {
   854→		if l.Name == labels.MetricName && !model.UTF8Validation.IsValidMetricName(l.Value) {
   855→			return fmt.Errorf("invalid metric name: %v", l.Value)
   856→		}
   857→		if !model.UTF8Validation.IsValidLabelName(l.Name) {
   858→			return fmt.Errorf("invalid label name: %v", l.Name)
   859→		}
   860→		if !model.LabelValue(l.Value).IsValid() {
   861→			return fmt.Errorf("invalid label value: %v", l.Value)
   862→		}
   863→		if i > 0 && l.Name == ls[i-1].Name {
   864→			return fmt.Errorf("duplicate label with name: %v", l.Name)
   865→		}
   866→	}
   867→	return nil
   868→}
