   896→// FromLabelMatchers converts protobuf label matchers to Prometheus label matchers.
   897→func FromLabelMatchers(matchers []*prompb.LabelMatcher) ([]*labels.Matcher, error) {
   898→	result := make([]*labels.Matcher, 0, len(matchers))
   899→	for _, matcher := range matchers {
   900→		var mtype labels.MatchType
   901→		switch matcher.Type {
   902→		case prompb.LabelMatcher_EQ:
   903→			mtype = labels.MatchEqual
   904→		case prompb.LabelMatcher_NEQ:
   905→			mtype = labels.MatchNotEqual
   906→		case prompb.LabelMatcher_RE:
   907→			mtype = labels.MatchRegexp
   908→		case prompb.LabelMatcher_NRE:
