   966→func DecodeOTLPWriteRequest(r *http.Request) (pmetricotlp.ExportRequest, error) {
   967→	contentType := r.Header.Get("Content-Type")
   968→	var decoderFunc func(buf []byte) (pmetricotlp.ExportRequest, error)
   969→	switch contentType {
   970→	case pbContentType:
   971→		decoderFunc = func(buf []byte) (pmetricotlp.ExportRequest, error) {
   972→			req := pmetricotlp.NewExportRequest()
   973→			return req, req.UnmarshalProto(buf)
   974→		}
   975→
   976→	case jsonContentType:
   977→		decoderFunc = func(buf []byte) (pmetricotlp.ExportRequest, error) {
   978→			req := pmetricotlp.NewExportRequest()
   979→			return req, req.UnmarshalJSON(buf)
   980→		}
   981→
   982→	default:
   983→		return pmetricotlp.NewExportRequest(), fmt.Errorf("unsupported content type: %s, supported: [%s, %s]", contentType, jsonContentType, pbContentType)
   984→	}
   985→
   986→	reader := r.Body
   987→	// Handle compression.
   988→	switch r.Header.Get("Content-Encoding") {
   989→	case "gzip":
   990→		gr, err := gzip.NewReader(reader)
   991→		if err != nil {
   992→			return pmetricotlp.NewExportRequest(), err
   993→		}
   994→		reader = gr
   995→
   996→	case "":
   997→		// No compression.
   998→
   999→	default:
  1000→		return pmetricotlp.NewExportRequest(), fmt.Errorf("unsupported compression: %s. Only \"gzip\" or no compression supported", r.Header.Get("Content-Encoding"))
  1001→	}
  1002→
  1003→	body, err := io.ReadAll(reader)
  1004→	if err != nil {
  1005→		r.Body.Close()
  1006→		return pmetricotlp.NewExportRequest(), err
  1007→	}
  1008→	if err = r.Body.Close(); err != nil {
  1009→		return pmetricotlp.NewExportRequest(), err
  1010→	}
  1011→	otlpReq, err := decoderFunc(body)
  1012→	if err != nil {
  1013→		return pmetricotlp.NewExportRequest(), err
  1014→	}
  1015→
  1016→	return otlpReq, nil
  1017→}
