    63→// DecodeReadRequest reads a remote.Request from a http.Request.
    64→func DecodeReadRequest(r *http.Request) (*prompb.ReadRequest, error) {
    65→	compressed, err := io.ReadAll(io.LimitReader(r.Body, decodeReadLimit))
    66→	if err != nil {
    67→		return nil, err
    68→	}
    69→
    70→	reqBuf, err := snappy.Decode(nil, compressed)
    71→	if err != nil {
    72→		return nil, err
    73→	}
    74→
    75→	var req prompb.ReadRequest
    76→	if err := proto.Unmarshal(reqBuf, &req); err != nil {
    77→		return nil, err
    78→	}
    79→
    80→	return &req, nil
    81→}
    82→
    83→// EncodeReadResponse writes a remote.Response to a http.ResponseWriter.
    84→func EncodeReadResponse(resp *prompb.ReadResponse, w http.ResponseWriter) error {
    85→	data, err := proto.Marshal(resp)
    86→	if err != nil {
    87→		return err
    88→	}
    89→
    90→	compressed := snappy.Encode(nil, data)
    91→	_, err = w.Write(compressed)
    92→	return err
    93→}
