    95→// ToQuery builds a Query proto.
    96→func ToQuery(from, to int64, matchers []*labels.Matcher, hints *storage.SelectHints) (*prompb.Query, error) {
    97→	ms, err := ToLabelMatchers(matchers)
    98→	if err != nil {
    99→		return nil, err
   100→	}
   101→
   102→	var rp *prompb.ReadHints
   103→	if hints != nil {
   104→		rp = &prompb.ReadHints{
   105→			StartMs:  hints.Start,
   106→			EndMs:    hints.End,
   107→			StepMs:   hints.Step,
   108→			Func:     hints.Func,
   109→			Grouping: hints.Grouping,
   110→			By:       hints.By,
   111→			RangeMs:  hints.Range,
   112→		}
   113→	}
   114→
   115→	return &prompb.Query{
   116→		StartTimestampMs: from,
   117→		EndTimestampMs:   to,
   118→		Matchers:         ms,
   119→		Hints:            rp,
   120→	}, nil
   121→}
