   123→// ToQueryResult builds a QueryResult proto.
   124→func ToQueryResult(ss storage.SeriesSet, sampleLimit int) (*prompb.QueryResult, annotations.Annotations, error) {
   125→	numSamples := 0
   126→	resp := &prompb.QueryResult{}
   127→	var iter chunkenc.Iterator
   128→	for ss.Next() {
   129→		series := ss.At()
   130→		iter = series.Iterator(iter)
   131→
   132→		var (
   133→			samples    []prompb.Sample
   134→			histograms []prompb.Histogram
   135→		)
   136→
   137→		for valType := iter.Next(); valType != chunkenc.ValNone; valType = iter.Next() {
   138→			numSamples++
   139→			if sampleLimit > 0 && numSamples > sampleLimit {
   140→				return nil, ss.Warnings(), HTTPError{
   141→					msg:    fmt.Sprintf("exceeded sample limit (%d)", sampleLimit),
   142→					status: http.StatusBadRequest,
   143→				}
   144→			}
   145→
   146→			switch valType {
   147→			case chunkenc.ValFloat:
   148→				ts, val := iter.At()
   149→				samples = append(samples, prompb.Sample{
   150→					Timestamp: ts,
   151→					Value:     val,
   152→				})
   153→			case chunkenc.ValHistogram:
   154→				ts, h := iter.AtHistogram(nil)
   155→				histograms = append(histograms, prompb.FromIntHistogram(ts, h))
   156→			case chunkenc.ValFloatHistogram:
   157→				ts, fh := iter.AtFloatHistogram(nil)
   158→				histograms = append(histograms, prompb.FromFloatHistogram(ts, fh))
   159→			default:
   160→				return nil, ss.Warnings(), fmt.Errorf("unrecognized value type: %s", valType)
   161→			}
   162→		}
   163→		if err := iter.Err(); err != nil {
   164→			return nil, ss.Warnings(), err
   165→		}
   166→
   167→		resp.Timeseries = append(resp.Timeseries, &prompb.TimeSeries{
   168→			Labels:     prompb.FromLabels(series.Labels(), nil),
   169→			Samples:    samples,
   170→			Histograms: histograms,
   171→		})
   172→	}
   173→	return resp, ss.Warnings(), ss.Err()
   174→}
   175→
   176→// FromQueryResult unpacks and sorts a QueryResult proto.
   177→func FromQueryResult(sortSeries bool, res *prompb.QueryResult) storage.SeriesSet {
   178→	b := labels.NewScratchBuilder(0)
   179→	series := make([]storage.Series, 0, len(res.Timeseries))
   180→	for _, ts := range res.Timeseries {
   181→		if err := validateLabelsAndMetricName(ts.Labels); err != nil {
   182→			return errSeriesSet{err: err}
   183→		}
   184→		lbls := ts.ToLabels(&b, nil)
   185→		series = append(series, &concreteSeries{labels: lbls, floats: ts.Samples, histograms: ts.Histograms})
   186→	}
   187→
   188→	if sortSeries {
   189→		slices.SortFunc(series, func(a, b storage.Series) int {
   190→			return labels.Compare(a.Labels(), b.Labels())
   191→		})
   192→	}
   193→	return &concreteSeriesSet{
   194→		series: series,
   195→	}
   196→}
