   385→// concreteSeriesIterator implements storage.SeriesIterator.
   386→type concreteSeriesIterator struct {
   387→	floatsCur     int
   388→	histogramsCur int
   389→	curValType    chunkenc.ValueType
   390→	series        *concreteSeries
   391→	err           error
   392→
   393→	// These are pre-filled with the current model histogram if curValType
   394→	// is ValHistogram or ValFloatHistogram, respectively.
   395→	curH  *histogram.Histogram
   396→	curFH *histogram.FloatHistogram
   397→}
   398→
   399→func newConcreteSeriesIterator(series *concreteSeries) chunkenc.Iterator {
   400→	return &concreteSeriesIterator{
   401→		floatsCur:     -1,
   402→		histogramsCur: -1,
   403→		curValType:    chunkenc.ValNone,
   404→		series:        series,
   405→	}
   406→}
   407→
   408→func (c *concreteSeriesIterator) reset(series *concreteSeries) {
   409→	c.floatsCur = -1
   410→	c.histogramsCur = -1
   411→	c.curValType = chunkenc.ValNone
   412→	c.series = series
   413→	c.err = nil
   414→}
   415→
   416→// Seek implements storage.SeriesIterator.
   417→func (c *concreteSeriesIterator) Seek(t int64) chunkenc.ValueType {
   418→	if c.err != nil {
   419→		return chunkenc.ValNone
   420→	}
   421→	if c.floatsCur == -1 {
   422→		c.floatsCur = 0
   423→	}
   424→	if c.histogramsCur == -1 {
   425→		c.histogramsCur = 0
   426→	}
   427→	if c.floatsCur >= len(c.series.floats) && c.histogramsCur >= len(c.series.histograms) {
   428→		return chunkenc.ValNone
   429→	}
   430→
   431→	// No-op check.
   432→	if (c.curValType == chunkenc.ValFloat && c.series.floats[c.floatsCur].Timestamp >= t) ||
   433→		((c.curValType == chunkenc.ValHistogram || c.curValType == chunkenc.ValFloatHistogram) && c.series.histograms[c.histogramsCur].Timestamp >= t) {
   434→		return c.curValType
   435→	}
   436→
   437→	c.curValType = chunkenc.ValNone
   438→
   439→	// Binary search between current position and end for both float and histograms samples.
   440→	c.floatsCur += sort.Search(len(c.series.floats)-c.floatsCur, func(n int) bool {
   441→		return c.series.floats[n+c.floatsCur].Timestamp >= t
   442→	})
   443→	c.histogramsCur += sort.Search(len(c.series.histograms)-c.histogramsCur, func(n int) bool {
   444→		return c.series.histograms[n+c.histogramsCur].Timestamp >= t
   445→	})
   446→	switch {
   447→	case c.floatsCur < len(c.series.floats) && c.histogramsCur < len(c.series.histograms):
   448→		// If float samples and histogram samples have overlapping timestamps prefer the float samples.
   449→		if c.series.floats[c.floatsCur].Timestamp <= c.series.histograms[c.histogramsCur].Timestamp {
   450→			c.curValType = chunkenc.ValFloat
   451→		} else {
   452→			c.curValType = chunkenc.ValHistogram
   453→		}
   454→		// When the timestamps do not overlap the cursor for the non-selected sample type has advanced too
   455→		// far; we decrement it back down here.
   456→		if c.series.floats[c.floatsCur].Timestamp != c.series.histograms[c.histogramsCur].Timestamp {
   457→			if c.curValType == chunkenc.ValFloat {
   458→				c.histogramsCur--
   459→			} else {
   460→				c.floatsCur--
   461→			}
   462→		}
   463→	case c.floatsCur < len(c.series.floats):
   464→		c.curValType = chunkenc.ValFloat
   465→	case c.histogramsCur < len(c.series.histograms):
   466→		c.curValType = chunkenc.ValHistogram
   467→	}
   468→	if c.curValType == chunkenc.ValHistogram {
   469→		c.setCurrentHistogram()
   470→	}
   471→	if c.err != nil {
   472→		c.curValType = chunkenc.ValNone
   473→	}
   474→	return c.curValType
   475→}
   476→
   477→// setCurrentHistogram pre-fills either the curH or the curFH field with a
   478→// converted model histogram and sets c.curValType accordingly. It validates the
   479→// histogram and sets c.err accordingly. This all has to be done in Seek() and
   480→// Next() already so that we know if the histogram we got from the remote-read
   481→// source is valid or not before we allow the AtHistogram()/AtFloatHistogram()
   482→// call.
   483→func (c *concreteSeriesIterator) setCurrentHistogram() {
   484→	pbH := c.series.histograms[c.histogramsCur]
   485→
   486→	// Basic schema check first.
   487→	schema := pbH.Schema
   488→	if !histogram.IsKnownSchema(schema) {
   489→		c.err = histogram.UnknownSchemaError(schema)
   490→		return
   491→	}
   492→
   493→	if pbH.IsFloatHistogram() {
   494→		c.curValType = chunkenc.ValFloatHistogram
   495→		mFH := pbH.ToFloatHistogram()
   496→		if mFH.Schema > histogram.ExponentialSchemaMax && mFH.Schema <= histogram.ExponentialSchemaMaxReserved {
   497→			// This is a very slow path, but it should only happen if the
   498→			// sample is from a newer Prometheus version that supports higher
   499→			// resolution.
   500→			if err := mFH.ReduceResolution(histogram.ExponentialSchemaMax); err != nil {
   501→				c.err = err
   502→				return
   503→			}
   504→		}
   505→		if err := mFH.Validate(); err != nil {
   506→			c.err = err
   507→			return
   508→		}
   509→		c.curFH = mFH
   510→		return
   511→	}
   512→	c.curValType = chunkenc.ValHistogram
   513→	mH := pbH.ToIntHistogram()
   514→	if mH.Schema > histogram.ExponentialSchemaMax && mH.Schema <= histogram.ExponentialSchemaMaxReserved {
   515→		// This is a very slow path, but it should only happen if the
   516→		// sample is from a newer Prometheus version that supports higher
   517→		// resolution.
   518→		if err := mH.ReduceResolution(histogram.ExponentialSchemaMax); err != nil {
   519→			c.err = err
   520→			return
   521→		}
   522→	}
   523→	if err := mH.Validate(); err != nil {
   524→		c.err = err
   525→		return
   526→	}
   527→	c.curH = mH
   528→}
