    63→// DecodeReadRequest reads a remote.Request from a http.Request.
    64→func DecodeReadRequest(r *http.Request) (*prompb.ReadRequest, error) {
    65→	compressed, err := io.ReadAll(io.LimitReader(r.Body, decodeReadLimit))
    66→	if err != nil {
    67→		return nil, err
    68→	}
    69→
    70→	reqBuf, err := snappy.Decode(nil, compressed)
    71→	if err != nil {
    72→		return nil, err
    73→	}
    74→
    75→	var req prompb.ReadRequest
    76→	if err := proto.Unmarshal(reqBuf, &req); err != nil {
    77→		return nil, err
    78→	}
    79→
    80→	return &req, nil
