   218→// StreamChunkedReadResponses iterates over series, builds chunks and streams those to the caller.
   219→// It expects Series set with populated chunks.
   220→func StreamChunkedReadResponses(
   221→	stream io.Writer,
   222→	queryIndex int64,
   223→	ss storage.ChunkSeriesSet,
   224→	sortedExternalLabels []prompb.Label,
   225→	maxBytesInFrame int,
   226→	marshalPool *sync.Pool,
   227→) (annotations.Annotations, error) {
   228→	var (
   229→		chks []prompb.Chunk
   230→		lbls []prompb.Label
   231→		iter chunks.Iterator
   232→	)
   233→
   234→	for ss.Next() {
   235→		series := ss.At()
   236→		iter = series.Iterator(iter)
   237→		lbls = MergeLabels(prompb.FromLabels(series.Labels(), lbls), sortedExternalLabels)
   238→
   239→		maxDataLength := maxBytesInFrame
   240→		for _, lbl := range lbls {
   241→			maxDataLength -= lbl.Size()
   242→		}
   243→		frameBytesLeft := maxDataLength
   244→
   245→		isNext := iter.Next()
   246→
   247→		// Send at most one series per frame; series may be split over multiple frames according to maxBytesInFrame.
   248→		for isNext {
   249→			chk := iter.At()
   250→
   251→			if chk.Chunk == nil {
   252→				return ss.Warnings(), fmt.Errorf("StreamChunkedReadResponses: found not populated chunk returned by SeriesSet at ref: %v", chk.Ref)
   253→			}
   254→
   255→			// Cut the chunk.
   256→			chks = append(chks, prompb.Chunk{
   257→				MinTimeMs: chk.MinTime,
   258→				MaxTimeMs: chk.MaxTime,
   259→				Type:      prompb.Chunk_Encoding(chk.Chunk.Encoding()),
   260→				Data:      chk.Chunk.Bytes(),
   261→			})
   262→			frameBytesLeft -= chks[len(chks)-1].Size()
   263→
   264→			// We are fine with minor inaccuracy of max bytes per frame. The inaccuracy will be max of full chunk size.
   265→			isNext = iter.Next()
   266→			if frameBytesLeft > 0 && isNext {
   267→				continue
   268→			}
   269→
   270→			resp := &prompb.ChunkedReadResponse{
   271→				ChunkedSeries: []*prompb.ChunkedSeries{
   272→					{Labels: lbls, Chunks: chks},
   273→				},
   274→				QueryIndex: queryIndex,
   275→			}
   276→
   277→			b, err := resp.PooledMarshal(marshalPool)
   278→			if err != nil {
   279→				return ss.Warnings(), fmt.Errorf("marshal ChunkedReadResponse: %w", err)
   280→			}
   281→
   282→			if _, err := stream.Write(b); err != nil {
   283→				return ss.Warnings(), fmt.Errorf("write to stream: %w", err)
   284→			}
   285→
   286→			// We immediately flush the Write() so it is safe to return to the pool.
   287→			marshalPool.Put(&b)
   288→			chks = chks[:0]
   289→			frameBytesLeft = maxDataLength
   290→		}
   291→		if err := iter.Err(); err != nil {
   292→			return ss.Warnings(), err
   293→		}
   294→	}
   295→	return ss.Warnings(), ss.Err()
   296→}
