   298→// MergeLabels merges two sets of sorted proto labels, preferring those in
   299→// primary to those in secondary when there is an overlap.
   300→func MergeLabels(primary, secondary []prompb.Label) []prompb.Label {
   301→	result := make([]prompb.Label, 0, len(primary)+len(secondary))
   302→	i, j := 0, 0
   303→	for i < len(primary) && j < len(secondary) {
   304→		switch {
   305→		case primary[i].Name < secondary[j].Name:
   306→			result = append(result, primary[i])
   307→			i++
   308→		case primary[i].Name > secondary[j].Name:
   309→			result = append(result, secondary[j])
   310→			j++
   311→		default:
   312→			result = append(result, primary[i])
   313→			i++
   314→			j++
   315→		}
   316→	}
   317→	for ; i < len(primary); i++ {
   318→		result = append(result, primary[i])
   319→	}
   320→	for ; j < len(secondary); j++ {
   321→		result = append(result, secondary[j])
   322→	}
   323→	return result
   324→}
