   377→func (c *concreteSeries) Iterator(it chunkenc.Iterator) chunkenc.Iterator {
   378→	if csi, ok := it.(*concreteSeriesIterator); ok {
   379→		csi.reset(c)
   380→		return csi
   381→	}
   382→	return newConcreteSeriesIterator(c)
   383→}
   384→
   385→// concreteSeriesIterator implements storage.SeriesIterator.
   386→type concreteSeriesIterator struct {
   387→	floatsCur     int
   388→	histogramsCur int
   389→	curValType    chunkenc.ValueType
   390→	series        *concreteSeries
   391→	err           error
   392→
   393→	// These are pre-filled with the current model histogram if curValType
   394→	// is ValHistogram or ValFloatHistogram, respectively.
   395→	curH  *histogram.Histogram
   396→	curFH *histogram.FloatHistogram
   397→}
   398→
   399→func newConcreteSeriesIterator(series *concreteSeries) chunkenc.Iterator {
   400→	return &concreteSeriesIterator{
   401→		floatsCur:     -1,
   402→		histogramsCur: -1,
   403→		curValType:    chunkenc.ValNone,
   404→		series:        series,
   405→	}
   406→}
   407→
   408→func (c *concreteSeriesIterator) reset(series *concreteSeries) {
   409→	c.floatsCur = -1
   410→	c.histogramsCur = -1
   411→	c.curValType = chunkenc.ValNone
   412→	c.series = series
   413→	c.err = nil
   414→}
   415→
   416→// Seek implements storage.SeriesIterator.
   417→func (c *concreteSeriesIterator) Seek(t int64) chunkenc.ValueType {
   418→	if c.err != nil {
   419→		return chunkenc.ValNone
   420→	}
   421→	if c.floatsCur == -1 {
   422→		c.floatsCur = 0
   423→	}
   424→	if c.histogramsCur == -1 {
   425→		c.histogramsCur = 0
   426→	}
   427→	if c.floatsCur >= len(c.series.floats) && c.histogramsCur >= len(c.series.histograms) {
   428→		return chunkenc.ValNone
   429→	}
   430→
   431→	// No-op check.
   432→	if (c.curValType == chunkenc.ValFloat && c.series.floats[c.floatsCur].Timestamp >= t) ||
   433→		((c.curValType == chunkenc.ValHistogram || c.curValType == chunkenc.ValFloatHistogram) && c.series.histograms[c.histogramsCur].Timestamp >= t) {
   434→		return c.curValType
   435→	}
   436→
   437→	c.curValType = chunkenc.ValNone
   438→
   439→	// Binary search between current position and end for both float and histograms samples.
   440→	c.floatsCur += sort.Search(len(c.series.floats)-c.floatsCur, func(n int) bool {
   441→		return c.series.floats[n+c.floatsCur].Timestamp >= t
   442→	})
   443→	c.histogramsCur += sort.Search(len(c.series.histograms)-c.histogramsCur, func(n int) bool {
   444→		return c.series.histograms[n+c.histogramsCur].Timestamp >= t
   445→	})
   446→	switch {
   447→	case c.floatsCur < len(c.series.floats) && c.histogramsCur < len(c.series.histograms):
   448→		// If float samples and histogram samples have overlapping timestamps prefer the float samples.
   449→		if c.series.floats[c.floatsCur].Timestamp <= c.series.histograms[c.histogramsCur].Timestamp {
   450→			c.curValType = chunkenc.ValFloat
   451→		} else {
   452→			c.curValType = chunkenc.ValHistogram
   453→		}
   454→		// When the timestamps do not overlap the cursor for the non-selected sample type has advanced too
   455→		// far; we decrement it back down here.
   456→		if c.series.floats[c.floatsCur].Timestamp != c.series.histograms[c.histogramsCur].Timestamp {
   457→			if c.curValType == chunkenc.ValFloat {
   458→				c.histogramsCur--
   459→			} else {
   460→				c.floatsCur--
   461→			}
   462→		}
   463→	case c.floatsCur < len(c.series.floats):
   464→		c.curValType = chunkenc.ValFloat
   465→	case c.histogramsCur < len(c.series.histograms):
   466→		c.curValType = chunkenc.ValHistogram
   467→	}
   468→	if c.curValType == chunkenc.ValHistogram {
   469→		c.setCurrentHistogram()
   470→	}
   471→	if c.err != nil {
   472→		c.curValType = chunkenc.ValNone
   473→	}
   474→	return c.curValType
   475→}
   476→
   477→// setCurrentHistogram pre-fills either the curH or the curFH field with a
   478→// converted model histogram and sets c.curValType accordingly. It validates the
   479→// histogram and sets c.err accordingly. This all has to be done in Seek() and
   480→// Next() already so that we know if the histogram we got from the remote-read
   481→// source is valid or not before we allow the AtHistogram()/AtFloatHistogram()
   482→// call.
   483→func (c *concreteSeriesIterator) setCurrentHistogram() {
   484→	pbH := c.series.histograms[c.histogramsCur]
   485→
   486→	// Basic schema check first.
   487→	schema := pbH.Schema
   488→	if !histogram.IsKnownSchema(schema) {
   489→		c.err = histogram.UnknownSchemaError(schema)
   490→		return
   491→	}
   492→
   493→	if pbH.IsFloatHistogram() {
   494→		c.curValType = chunkenc.ValFloatHistogram
   495→		mFH := pbH.ToFloatHistogram()
   496→		if mFH.Schema > histogram.ExponentialSchemaMax && mFH.Schema <= histogram.ExponentialSchemaMaxReserved {
   497→			// This is a very slow path, but it should only happen if the
   498→			// sample is from a newer Prometheus version that supports higher
   499→			// resolution.
   500→			if err := mFH.ReduceResolution(histogram.ExponentialSchemaMax); err != nil {
   501→				c.err = err
   502→				return
   503→			}
   504→		}
   505→		if err := mFH.Validate(); err != nil {
   506→			c.err = err
   507→			return
   508→		}
   509→		c.curFH = mFH
   510→		return
   511→	}
   512→	c.curValType = chunkenc.ValHistogram
   513→	mH := pbH.ToIntHistogram()
   514→	if mH.Schema > histogram.ExponentialSchemaMax && mH.Schema <= histogram.ExponentialSchemaMaxReserved {
   515→		// This is a very slow path, but it should only happen if the
   516→		// sample is from a newer Prometheus version that supports higher
   517→		// resolution.
   518→		if err := mH.ReduceResolution(histogram.ExponentialSchemaMax); err != nil {
   519→			c.err = err
   520→			return
   521→		}
   522→	}
   523→	if err := mH.Validate(); err != nil {
   524→		c.err = err
   525→		return
   526→	}
   527→	c.curH = mH
   528→}
   529→
   530→// At implements chunkenc.Iterator.
   531→func (c *concreteSeriesIterator) At() (t int64, v float64) {
   532→	if c.curValType != chunkenc.ValFloat {
   533→		panic("iterator is not on a float sample")
   534→	}
   535→	s := c.series.floats[c.floatsCur]
   536→	return s.Timestamp, s.Value
   537→}
   538→
   539→// AtHistogram implements chunkenc.Iterator.
   540→func (c *concreteSeriesIterator) AtHistogram(*histogram.Histogram) (int64, *histogram.Histogram) {
   541→	if c.curValType != chunkenc.ValHistogram {
   542→		panic("iterator is not on an integer histogram sample")
   543→	}
   544→	return c.series.histograms[c.histogramsCur].Timestamp, c.curH
   545→}
   546→
   547→// AtFloatHistogram implements chunkenc.Iterator.
   548→func (c *concreteSeriesIterator) AtFloatHistogram(*histogram.FloatHistogram) (int64, *histogram.FloatHistogram) {
   549→	switch c.curValType {
   550→	case chunkenc.ValFloatHistogram:
   551→		return c.series.histograms[c.histogramsCur].Timestamp, c.curFH
   552→	case chunkenc.ValHistogram:
   553→		return c.series.histograms[c.histogramsCur].Timestamp, c.curH.ToFloat(nil)
   554→	default:
   555→		panic("iterator is not on a histogram sample")
   556→	}
   557→}
   558→
   559→// AtT implements chunkenc.Iterator.
   560→func (c *concreteSeriesIterator) AtT() int64 {
   561→	if c.curValType == chunkenc.ValHistogram || c.curValType == chunkenc.ValFloatHistogram {
   562→		return c.series.histograms[c.histogramsCur].Timestamp
   563→	}
   564→	return c.series.floats[c.floatsCur].Timestamp
   565→}
   566→
   567→// TODO(krajorama): implement AtST. Maybe. concreteSeriesIterator is used
   568→// for turning query results into an iterable, but query results do not have ST.
   569→func (*concreteSeriesIterator) AtST() int64 {
   570→	return 0
   571→}
   572→
   573→const noTS = int64(math.MaxInt64)
   574→
   575→// Next implements chunkenc.Iterator.
   576→func (c *concreteSeriesIterator) Next() chunkenc.ValueType {
   577→	if c.err != nil {
   578→		return chunkenc.ValNone
   579→	}
   580→	peekFloatTS := noTS
   581→	if c.floatsCur+1 < len(c.series.floats) {
   582→		peekFloatTS = c.series.floats[c.floatsCur+1].Timestamp
   583→	}
   584→	peekHistTS := noTS
   585→	if c.histogramsCur+1 < len(c.series.histograms) {
   586→		peekHistTS = c.series.histograms[c.histogramsCur+1].Timestamp
   587→	}
   588→	c.curValType = chunkenc.ValNone
   589→	switch {
   590→	case peekFloatTS < peekHistTS:
   591→		c.floatsCur++
   592→		c.curValType = chunkenc.ValFloat
   593→	case peekHistTS < peekFloatTS:
   594→		c.histogramsCur++
   595→		c.curValType = chunkenc.ValHistogram
   596→	case peekFloatTS == noTS && peekHistTS == noTS:
   597→		// This only happens when the iterator is exhausted; we set the cursors off the end to prevent
   598→		// Seek() from returning anything afterwards.
   599→		c.floatsCur = len(c.series.floats)
   600→		c.histogramsCur = len(c.series.histograms)
   601→	default:
   602→		// Prefer float samples to histogram samples if there's a conflict. We advance the cursor for histograms
   603→		// anyway otherwise the histogram sample will get selected on the next call to Next().
   604→		c.floatsCur++
   605→		c.histogramsCur++
   606→		c.curValType = chunkenc.ValFloat
   607→	}
   608→
   609→	if c.curValType == chunkenc.ValHistogram {
   610→		c.setCurrentHistogram()
   611→	}
   612→	if c.err != nil {
   613→		c.curValType = chunkenc.ValNone
   614→	}
   615→	return c.curValType
   616→}
   617→
   618→// Err implements chunkenc.Iterator.
   619→func (c *concreteSeriesIterator) Err() error {
   620→	return c.err
   621→}
   622→
   623→// chunkedSeriesSet implements storage.SeriesSet.
   624→type chunkedSeriesSet struct {
   625→	chunkedReader *ChunkedReader
   626→	respBody      io.ReadCloser
   627→	mint, maxt    int64
   628→	cancel        func(error)
   629→
   630→	current   storage.Series
   631→	err       error
   632→	exhausted bool
   633→}
   634→
   635→func NewChunkedSeriesSet(chunkedReader *ChunkedReader, respBody io.ReadCloser, mint, maxt int64, cancel func(error)) storage.SeriesSet {
   636→	return &chunkedSeriesSet{
   637→		chunkedReader: chunkedReader,
   638→		respBody:      respBody,
   639→		mint:          mint,
   640→		maxt:          maxt,
   641→		cancel:        cancel,
   642→	}
   643→}
   644→
   645→// Next return true if there is a next series and false otherwise. It will
   646→// block until the next series is available.
   647→func (s *chunkedSeriesSet) Next() bool {
   648→	if s.exhausted {
   649→		// Don't try to read the next series again.
   650→		// This prevents errors like "http: read on closed response body" if Next() is called after it has already returned false.
   651→		return false
   652→	}
   653→
   654→	res := &prompb.ChunkedReadResponse{}
   655→
   656→	err := s.chunkedReader.NextProto(res)
   657→	if err != nil {
   658→		if !errors.Is(err, io.EOF) {
   659→			s.err = err
   660→			_, _ = io.Copy(io.Discard, s.respBody)
   661→		}
   662→
   663→		_ = s.respBody.Close()
   664→		s.cancel(err)
   665→		s.exhausted = true
   666→
   667→		return false
   668→	}
   669→
   670→	s.current = &chunkedSeries{
   671→		ChunkedSeries: prompb.ChunkedSeries{
   672→			Labels: res.ChunkedSeries[0].Labels,
   673→			Chunks: res.ChunkedSeries[0].Chunks,
   674→		},
   675→		mint: s.mint,
   676→		maxt: s.maxt,
   677→	}
   678→
   679→	return true
   680→}
   681→
   682→func (s *chunkedSeriesSet) At() storage.Series {
   683→	return s.current
   684→}
   685→
   686→func (s *chunkedSeriesSet) Err() error {
   687→	return s.err
   688→}
   689→
   690→func (*chunkedSeriesSet) Warnings() annotations.Annotations {
   691→	return nil
   692→}
   693→
   694→type chunkedSeries struct {
   695→	prompb.ChunkedSeries
   696→	mint, maxt int64
   697→}
   698→
   699→var _ storage.Series = &chunkedSeries{}
   700→
   701→func (s *chunkedSeries) Labels() labels.Labels {
   702→	b := labels.NewScratchBuilder(0)
   703→	return s.ToLabels(&b, nil)
   704→}
   705→
   706→func (s *chunkedSeries) Iterator(it chunkenc.Iterator) chunkenc.Iterator {
   707→	csIt, ok := it.(*chunkedSeriesIterator)
   708→	if ok {
   709→		csIt.reset(s.Chunks, s.mint, s.maxt)
   710→		return csIt
   711→	}
   712→	return newChunkedSeriesIterator(s.Chunks, s.mint, s.maxt)
   713→}
   714→
   715→type chunkedSeriesIterator struct {
   716→	chunks     []prompb.Chunk
   717→	idx        int
   718→	cur        chunkenc.Iterator
   719→	valType    chunkenc.ValueType
   720→	mint, maxt int64
   721→
   722→	err error
   723→}
   724→
   725→var _ chunkenc.Iterator = &chunkedSeriesIterator{}
   726→
   727→func newChunkedSeriesIterator(chunks []prompb.Chunk, mint, maxt int64) *chunkedSeriesIterator {
   728→	it := &chunkedSeriesIterator{}
   729→	it.reset(chunks, mint, maxt)
   730→	return it
   731→}
   732→
   733→func (it *chunkedSeriesIterator) Next() chunkenc.ValueType {
   734→	if it.err != nil {
   735→		return chunkenc.ValNone
   736→	}
   737→	if len(it.chunks) == 0 {
   738→		return chunkenc.ValNone
   739→	}
   740→
   741→	for it.valType = it.cur.Next(); it.valType != chunkenc.ValNone; it.valType = it.cur.Next() {
   742→		atT := it.AtT()
   743→		if atT > it.maxt {
   744→			it.chunks = nil // Exhaust this iterator so follow-up calls to Next or Seek return fast.
   745→			return chunkenc.ValNone
   746→		}
   747→		if atT >= it.mint {
   748→			return it.valType
   749→		}
   750→	}
   751→
   752→	if it.idx >= len(it.chunks)-1 {
   753→		it.valType = chunkenc.ValNone
   754→	} else {
   755→		it.idx++
   756→		it.resetIterator()
   757→		it.valType = it.Next()
   758→	}
   759→
   760→	return it.valType
   761→}
   762→
   763→func (it *chunkedSeriesIterator) Seek(t int64) chunkenc.ValueType {
   764→	if it.err != nil {
   765→		return chunkenc.ValNone
   766→	}
   767→	if len(it.chunks) == 0 {
   768→		return chunkenc.ValNone
   769→	}
   770→
   771→	startIdx := it.idx
   772→	it.idx += sort.Search(len(it.chunks)-startIdx, func(i int) bool {
   773→		return it.chunks[startIdx+i].MaxTimeMs >= t
   774→	})
   775→	if it.idx > startIdx {
   776→		it.resetIterator()
   777→	} else {
   778→		ts := it.cur.AtT()
   779→		if ts >= t {
   780→			return it.valType
   781→		}
   782→	}
   783→
   784→	for it.valType = it.cur.Next(); it.valType != chunkenc.ValNone; it.valType = it.cur.Next() {
   785→		ts := it.cur.AtT()
   786→		if ts > it.maxt {
   787→			it.chunks = nil // Exhaust this iterator so follow-up calls to Next or Seek return fast.
   788→			return chunkenc.ValNone
   789→		}
   790→		if ts >= t && ts >= it.mint {
   791→			return it.valType
   792→		}
   793→	}
   794→
   795→	it.valType = chunkenc.ValNone
   796→	return it.valType
   797→}
   798→
   799→func (it *chunkedSeriesIterator) resetIterator() {
   800→	if it.idx < len(it.chunks) {
   801→		chunk := it.chunks[it.idx]
   802→
   803→		decodedChunk, err := chunkenc.FromData(chunkenc.Encoding(chunk.Type), chunk.Data)
   804→		if err != nil {
   805→			it.err = err
   806→			return
   807→		}
   808→
   809→		it.cur = decodedChunk.Iterator(nil)
   810→	} else {
   811→		it.cur = chunkenc.NewNopIterator()
   812→	}
   813→}
   814→
   815→func (it *chunkedSeriesIterator) reset(chunks []prompb.Chunk, mint, maxt int64) {
   816→	it.chunks = chunks
   817→	it.mint = mint
   818→	it.maxt = maxt
   819→	it.idx = 0
   820→	if len(chunks) > 0 {
   821→		it.resetIterator()
   822→	}
   823→}
   824→
   825→func (it *chunkedSeriesIterator) At() (ts int64, v float64) {
   826→	return it.cur.At()
   827→}
   828→
   829→func (it *chunkedSeriesIterator) AtHistogram(h *histogram.Histogram) (int64, *histogram.Histogram) {
   830→	return it.cur.AtHistogram(h)
   831→}
   832→
   833→func (it *chunkedSeriesIterator) AtFloatHistogram(fh *histogram.FloatHistogram) (int64, *histogram.FloatHistogram) {
   834→	return it.cur.AtFloatHistogram(fh)
   835→}
   836→
   837→func (it *chunkedSeriesIterator) AtT() int64 {
   838→	return it.cur.AtT()
   839→}
   840→
   841→// TODO(krajorama): test AtST once we have a chunk format that provides ST.
   842→func (it *chunkedSeriesIterator) AtST() int64 {
   843→	return it.cur.AtST()
   844→}
   845→
   846→func (it *chunkedSeriesIterator) Err() error {
   847→	return it.err
   848→}
   849→
   850→// validateLabelsAndMetricName validates the label names/values and metric names returned from remote read,
   851→// also making sure that there are no labels with duplicate names.
   852→func validateLabelsAndMetricName(ls []prompb.Label) error {
   853→	for i, l := range ls {
   854→		if l.Name == labels.MetricName && !model.UTF8Validation.IsValidMetricName(l.Value) {
   855→			return fmt.Errorf("invalid metric name: %v", l.Value)
   856→		}
   857→		if !model.UTF8Validation.IsValidLabelName(l.Name) {
   858→			return fmt.Errorf("invalid label name: %v", l.Name)
   859→		}
   860→		if !model.LabelValue(l.Value).IsValid() {
   861→			return fmt.Errorf("invalid label value: %v", l.Value)
   862→		}
   863→		if i > 0 && l.Name == ls[i-1].Name {
   864→			return fmt.Errorf("duplicate label with name: %v", l.Name)
   865→		}
   866→	}
   867→	return nil
   868→}
   869→
   870→// ToLabelMatchers converts Prometheus label matchers to protobuf label matchers.
   871→func ToLabelMatchers(matchers []*labels.Matcher) ([]*prompb.LabelMatcher, error) {
   872→	pbMatchers := make([]*prompb.LabelMatcher, 0, len(matchers))
   873→	for _, m := range matchers {
   874→		var mType prompb.LabelMatcher_Type
   875→		switch m.Type {
   876→		case labels.MatchEqual:
   877→			mType = prompb.LabelMatcher_EQ
   878→		case labels.MatchNotEqual:
   879→			mType = prompb.LabelMatcher_NEQ
   880→		case labels.MatchRegexp:
   881→			mType = prompb.LabelMatcher_RE
   882→		case labels.MatchNotRegexp:
   883→			mType = prompb.LabelMatcher_NRE
   884→		default:
   885→			return nil, errors.New("invalid matcher type")
   886→		}
   887→		pbMatchers = append(pbMatchers, &prompb.LabelMatcher{
   888→			Type:  mType,
   889→			Name:  m.Name,
   890→			Value: m.Value,
   891→		})
   892→	}
   893→	return pbMatchers, nil
   894→}
   895→
   896→// FromLabelMatchers converts protobuf label matchers to Prometheus label matchers.
   897→func FromLabelMatchers(matchers []*prompb.LabelMatcher) ([]*labels.Matcher, error) {
   898→	result := make([]*labels.Matcher, 0, len(matchers))
   899→	for _, matcher := range matchers {
   900→		var mtype labels.MatchType
   901→		switch matcher.Type {
   902→		case prompb.LabelMatcher_EQ:
   903→			mtype = labels.MatchEqual
   904→		case prompb.LabelMatcher_NEQ:
   905→			mtype = labels.MatchNotEqual
   906→		case prompb.LabelMatcher_RE:
   907→			mtype = labels.MatchRegexp
   908→		case prompb.LabelMatcher_NRE:
   909→			mtype = labels.MatchNotRegexp
   910→		default:
   911→			return nil, errors.New("invalid matcher type")
   912→		}
   913→		matcher, err := labels.NewMatcher(mtype, matcher.Name, matcher.Value)
   914→		if err != nil {
   915→			return nil, err
   916→		}
   917→		result = append(result, matcher)
   918→	}
   919→	return result, nil
   920→}
   921→
   922→// DecodeWriteRequest from an io.Reader into a prompb.WriteRequest, handling
   923→// snappy decompression.
   924→// Used also by documentation/examples/remote_storage.
   925→func DecodeWriteRequest(r io.Reader) (*prompb.WriteRequest, error) {
   926→	compressed, err := io.ReadAll(r)
   927→	if err != nil {
   928→		return nil, err
   929→	}
   930→
   931→	reqBuf, err := snappy.Decode(nil, compressed)
   932→	if err != nil {
   933→		return nil, err
   934→	}
   935→
   936→	var req prompb.WriteRequest
   937→	if err := proto.Unmarshal(reqBuf, &req); err != nil {
   938→		return nil, err
   939→	}
   940→
   941→	return &req, nil
   942→}
   943→
   944→// DecodeWriteV2Request from an io.Reader into a writev2.Request, handling
   945→// snappy decompression.
   946→// Used also by documentation/examples/remote_storage.
   947→func DecodeWriteV2Request(r io.Reader) (*writev2.Request, error) {
   948→	compressed, err := io.ReadAll(r)
   949→	if err != nil {
   950→		return nil, err
   951→	}
   952→
   953→	reqBuf, err := snappy.Decode(nil, compressed)
   954→	if err != nil {
   955→		return nil, err
   956→	}
   957→
   958→	var req writev2.Request
   959→	if err := proto.Unmarshal(reqBuf, &req); err != nil {
   960→		return nil, err
   961→	}
   962→
   963→	return &req, nil
   964→}
   965→
   966→func DecodeOTLPWriteRequest(r *http.Request) (pmetricotlp.ExportRequest, error) {
   967→	contentType := r.Header.Get("Content-Type")
   968→	var decoderFunc func(buf []byte) (pmetricotlp.ExportRequest, error)
   969→	switch contentType {
   970→	case pbContentType:
   971→		decoderFunc = func(buf []byte) (pmetricotlp.ExportRequest, error) {
   972→			req := pmetricotlp.NewExportRequest()
   973→			return req, req.UnmarshalProto(buf)
   974→		}
   975→
   976→	case jsonContentType:
   977→		decoderFunc = func(buf []byte) (pmetricotlp.ExportRequest, error) {
   978→			req := pmetricotlp.NewExportRequest()
   979→			return req, req.UnmarshalJSON(buf)
   980→		}
   981→
   982→	default:
   983→		return pmetricotlp.NewExportRequest(), fmt.Errorf("unsupported content type: %s, supported: [%s, %s]", contentType, jsonContentType, pbContentType)
   984→	}
   985→
   986→	reader := r.Body
   987→	// Handle compression.
   988→	switch r.Header.Get("Content-Encoding") {
   989→	case "gzip":
   990→		gr, err := gzip.NewReader(reader)
   991→		if err != nil {
   992→			return pmetricotlp.NewExportRequest(), err
   993→		}
   994→		reader = gr
   995→
   996→	case "":
   997→		// No compression.
   998→
   999→	default:
  1000→		return pmetricotlp.NewExportRequest(), fmt.Errorf("unsupported compression: %s. Only \"gzip\" or no compression supported", r.Header.Get("Content-Encoding"))
  1001→	}
  1002→
  1003→	body, err := io.ReadAll(reader)
  1004→	if err != nil {
  1005→		r.Body.Close()
  1006→		return pmetricotlp.NewExportRequest(), err
  1007→	}
  1008→	if err = r.Body.Close(); err != nil {
  1009→		return pmetricotlp.NewExportRequest(), err
  1010→	}
  1011→	otlpReq, err := decoderFunc(body)
  1012→	if err != nil {
  1013→		return pmetricotlp.NewExportRequest(), err
  1014→	}
  1015→
  1016→	return otlpReq, nil
  1017→}
